#include <bits/stdc++.h>
using namespace std;
const int MAXN = 100010;
long long n,m,t[MAXN * 4],a[MAXN];
void push_up(int u)
{
	t[u]=(t[u*2]+t[u*2+1]);
}
void build(int u,int l,int r)
{
	if(l==r)
	{
		t[u]=a[l];
		return ;
	}
	int mid=(l+r)/2;
	build(u*2,l,mid);
	build(u*2+1,mid+1,r);
	push_up(u);
}
void sqrtt(int u,int l,int r,int x,int y)
{
    if(t[u]==(r-l+1)) return ;
    if(l==r)
    {
        t[u]=sqrt(t[u]);
        return ;
    }
    int mid=(l+r)>>1;
    if(x<=mid) sqrtt(u*2,l,mid,x,y);
	if(y>mid) sqrtt(u*2+1,mid+1,r,x,y);
    push_up(u);
}
long long sum(int u,int l,int r,int x,int y)
{
	if(l>=x&&r<=y) return t[u];
	int mid=(l+r)/2;
	long long ans=0;
	if(x<=mid) ans+=sum(u*2,l,mid,x,y);
	if(y>mid) ans+=sum(u*2+1,mid+1,r,x,y);
	return ans;
}
int main()
{
    ios::sync_with_stdio(0);
    cin.tie(0),cout.tie(0);
	cin>>n;
	for(int i=1;i<=n;i++) cin>>a[i];
	build(1,1,n);
    cin>>m;
	while(m--)
	{
		long long op,x,y;
		cin>>op>>x>>y;
		if (x > y) {
			swap(x, y);
		}
		if(op==0)
		{
			sqrtt(1,1,n,x,y);
		}
		else cout<<sum(1,1,n,x,y)<<'\n';
	}
	return 0;
}
